mapper.select:
SELECT asr.id AS id, grade.grade_group_name AS gradeGroupName, cla.class_name AS className, stu.seat_no AS seatNo, stu.id AS studentId, stu.chinese_name AS studentName, stu.student_no AS studentNo, lacr.`name` AS courseName, asr.type AS type FROM activity_student_report asr LEFT JOIN student_info stu ON stu.id = asr.student_id LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON cla.grade_group = grade.id LEFT JOIN leisure_activity_courses_record lacr ON lacr.id = asr.lenson_id WHERE asr.deleted = 0
AND asr.activity_id = #{reqModel.activityId}
AND asr.lenson_id = #{reqModel.coursesId}
AND stu.class_id = #{reqModel.classId}
AND stu.chinese_name LIKE CONCAT('%', #{reqModel.studentName}, '%')
AND stu.student_no LIKE CONCAT('%', #{reqModel.studentNo}, '%')
AND asr.type IN (1,2,3)
AND asr.type IN (4,5)
AND stu.class_id IN
#{item}
ORDER BY CASE grade.grade WHEN '中六' THEN 1 WHEN '中五' THEN 2 WHEN '中四' THEN 3 WHEN '中三' THEN 4 WHEN '中二' THEN 5 WHEN '中一' THEN 6 WHEN '六年級' THEN 7 WHEN '五年級' THEN 8 WHEN '四年級' THEN 9 WHEN '三年級' THEN 10 WHEN '二年級' THEN 11 WHEN '一年級' THEN 12 WHEN '幼三' THEN 13 WHEN '幼二' THEN 14 WHEN '幼一' THEN 15 ELSE 999 END ASC, cla.class_serial_number DESC, stu.seat_no IS NULL, stu.seat_no ASC

SELECT asar.id AS id, stu.id AS studentId, grade.grade_group_name AS gradeGroupName, cla.class_name AS className, stu.seat_no AS seatNo, stu.chinese_name AS studentName, stu.student_no AS studentNo, asar.type AS type, asar.create_time AS createTime FROM activity_student_apply_report asar LEFT JOIN student_info stu ON stu.id = asar.student_id LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON cla.grade_group = grade.id WHERE asar.deleted = 0 AND asar.status = 3
AND asar.activity_id = #{reqModel.activityId}
AND asar.type = #{reqModel.type}
AND stu.class_id IN
#{item}
ORDER BY CASE grade.grade WHEN '中六' THEN 1 WHEN '中五' THEN 2 WHEN '中四' THEN 3 WHEN '中三' THEN 4 WHEN '中二' THEN 5 WHEN '中一' THEN 6 WHEN '六年級' THEN 7 WHEN '五年級' THEN 8 WHEN '四年級' THEN 9 WHEN '三年級' THEN 10 WHEN '二年級' THEN 11 WHEN '一年級' THEN 12 WHEN '幼三' THEN 13 WHEN '幼二' THEN 14 WHEN '幼一' THEN 15 ELSE 999 END ASC, cla.class_serial_number DESC, stu.seat_no IS NULL, stu.seat_no ASC

SELECT asar.id AS id, stu.id AS studentId, grade.grade_group_name AS gradeGroupName, cla.class_name AS className, stu.seat_no AS seatNo, stu.chinese_name AS studentName, stu.student_no AS studentNo, asar.type AS type, asar.create_time AS createTime FROM activity_student_apply_report asar LEFT JOIN student_info stu ON stu.id = asar.student_id LEFT JOIN sys_class cla ON cla.id = stu.class_id LEFT JOIN grade_group grade ON cla.grade_group = grade.id WHERE asar.deleted = 0
AND asar.activity_id = #{reqModel.activityId}
AND asar.type = #{reqModel.type}
AND stu.class_id = #{reqModel.classId}
AND stu.chinese_name LIKE CONCAT('%', #{reqModel.studentName}, '%')
AND stu.student_no LIKE CONCAT('%', #{reqModel.studentNo}, '%')
AND stu.class_id IN
#{item}
ORDER BY CASE grade.grade WHEN '中六' THEN 1 WHEN '中五' THEN 2 WHEN '中四' THEN 3 WHEN '中三' THEN 4 WHEN '中二' THEN 5 WHEN '中一' THEN 6 WHEN '六年級' THEN 7 WHEN '五年級' THEN 8 WHEN '四年級' THEN 9 WHEN '三年級' THEN 10 WHEN '二年級' THEN 11 WHEN '一年級' THEN 12 WHEN '幼三' THEN 13 WHEN '幼二' THEN 14 WHEN '幼一' THEN 15 ELSE 999 END ASC, cla.class_serial_number DESC, stu.seat_no IS NULL, stu.seat_no ASC, asar.type ASC
